#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N, B;
        scanf("%lld %lld", &N, &B);
        long long x = (N - 1) / B;
        long long y = (x * (x + 1)) / 2;
        printf("%lld\n", y);
    }
    return 0;
}

