import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long N = sc.nextLong();
            long B = sc.nextLong();
            long x = (N - 1) / B;
            long y = (x * (x + 1)) / 2;
            System.out.println(y);
        }
    }
}

