const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, B] = readline().split(' ').map(Number);
    const x = Math.floor((N - 1) / B);
    const y = Math.floor((x * (x + 1)) / 2);
    console.log(y);
}
